class Pubsub {
    constructor(){
        this.topics = {};
    }
    publish(name, args) {
        if (!this.topics[name]) {
            return false;
        }
        for(let key in this.topics[name]){
            const callback = this.topics[name];
            callback(args);
        }
    }

    subscribe(name, callback) {
        if (!this.topics[name]) {
            this.topics[name] = [];
        }
        this.topics[name].push(callback);
    }

    unsubscribe(name,callback) {
         if (!this.topics[name]) {
            return false;
         }
         this.topics[name].remove(callback);
    }
}


