class Chain {
    constructor(){
      this.fn = fn;
      this.nextFunc = null;
    }
    setNextFunc( nextFunc ){
      return this.nextFunc = nextFunc;
    }
    run() {
        var result = this.fn.apply( this, arguments );
        if ( result === &#039;next&#039; ){
            return this.nextFunc &amp;&amp; this.nextFunc.run.apply( this.nextFunc, arguments);
        }
        return result;
    }
}

